const pending: Message[] = [];
let raf = 0;

socket.onmessage = (event) => {
  pending.push(JSON.parse(event.data));
  if (raf) return;
  raf = requestAnimationFrame(() => {
    const batch = pending.splice(0);
    raf = 0;
    unstable_batchedUpdates(() => store.dispatch(messagesReceived(batch)));
  });
};

