import {useDeferredValue, useMemo, useState} from 'react';

export function DeferredFilter({items}: {items: readonly {id: string; label: string}[]}) {
  const [query, setQuery] = useState('');
  const deferredQuery = useDeferredValue(query);
  const isStale = query !== deferredQuery;
  const filtered = useMemo(() => {
    const needle = deferredQuery.trim().toLowerCase();
    return needle ? items.filter((item) => item.label.toLowerCase().includes(needle)) : items;
  }, [items, deferredQuery]);
  return <><input value={query} onChange={(event) => setQuery(event.target.value)} />{isStale && <span>Updating...</span>}<ResultList items={filtered} /></>;
}

